```class Solution {
public:
    int minSwaps(string s) {
        int n = s.length();
        int swaps = 0;
        for (int i = 0; i < n; i += 2) {
            if (s[i] != s[n - i - 1]) {
                swaps++;
            }
        }
        return swaps;
    }
};
```

